-- EASY (20 questions)
('foundation', 'tenses-advanced', 'intermediate', 'I _____ working at 5 PM tomorrow.', '["will work", "will be working", "will worked", "will be work"]', 1, 'Future continuous: will be + V-ing. Shows action in progress at specific future time. "Will be working at 5 PM" = ongoing at that moment.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ sleeping when you arrive.', '["will sleep", "will be sleeping", "will slept", "will be sleep"]', 1, 'Future continuous: will be + V-ing. Action in progress when another action happens. Pattern: will be + V-ing + when.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ studying all night.', '["will study", "will be studying", "will studied", "will be study"]', 1, 'Future continuous: will be + V-ing. Shows duration in future. "Will be studying all night" = continuous future action.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'At 10 AM, he _____ in a meeting.', '["will be sitting", "will sit", "will sat", "will be sit"]', 0, 'Future continuous: will be + V-ing for specific future time. "Will be sitting at 10 AM" = action in progress at that time.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'This time next week, we _____ to Mumbai.', '["will travel", "will be traveling", "will traveled", "will be travel"]', 1, 'Future continuous: will be + V-ing. "This time next week" = specific future moment. Shows action in progress at that time.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'I _____ my exam tomorrow morning.', '["will take", "will be taking", "will took", "will be take"]', 1, 'Future continuous: will be + V-ing. "Tomorrow morning" = specific future time. Action in progress during that period.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ dinner when we arrive.', '["will cook", "will be cooking", "will cooked", "will be cook"]', 1, 'Future continuous: will be + V-ing + when. Background action when another happens. Cooking = ongoing when arrival occurs.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ at the airport at 6 PM.', '["will wait", "will be waiting", "will waited", "will be wait"]', 1, 'Future continuous: will be + V-ing. Specific future time = action in progress. "Will be waiting at 6 PM" = ongoing at that moment.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'At noon, I _____ lunch.', '["will have", "will be having", "will had", "will be have"]', 1, 'Future continuous: will be + V-ing. "At noon" = specific time. Action in progress at that exact moment.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'Next month, we _____ our new office.', '["will use", "will be using", "will used", "will be use"]', 1, 'Future continuous: will be + V-ing. "Next month" = extended future period. Ongoing use during that time.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'I _____ you tomorrow at 3 PM.', '["will call", "will be calling", "will called", "will be call"]', 1, 'Future continuous: will be + V-ing. Polite/softer way to state future action. More tentative than "will call".', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ TV all evening.', '["will watch", "will be watching", "will watched", "will be watch"]', 1, 'Future continuous: will be + V-ing. "All evening" = duration. Action continues throughout that period.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ here for two hours.', '["will wait", "will be waiting", "will waited", "will be wait"]', 1, 'Future continuous: will be + V-ing + duration. "For two hours" = extended time. Ongoing action over that period.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'At midnight, he _____ home.', '["will drive", "will be driving", "will drove", "will be drive"]', 1, 'Future continuous: will be + V-ing. "At midnight" = specific time. Action in progress at that exact moment.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'This time tomorrow, I _____ on a beach.', '["will relax", "will be relaxing", "will relaxed", "will be relax"]', 1, 'Future continuous: will be + V-ing. "This time tomorrow" = exact future moment. Action in progress at that time.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'We _____ the project next week.', '["will complete", "will be completing", "will completed", "will be complete"]', 1, 'Future continuous: will be + V-ing. "Next week" = extended period. Work in progress during that time.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ for her exam all day.', '["will prepare", "will be preparing", "will prepared", "will be prepare"]', 1, 'Future continuous: will be + V-ing. "All day" = extended duration. Continuous preparation throughout the day.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ here when you call.', '["will work", "will be working", "will worked", "will be work"]', 1, 'Future continuous: will be + V-ing + when. Background action when another happens. Working = ongoing when call occurs.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'At 8 AM, I _____ to work.', '["will commute", "will be commuting", "will commuted", "will be commute"]', 1, 'Future continuous: will be + V-ing. "At 8 AM" = specific time. Action in progress at that moment (habitual future).', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'Next year, we _____ in a new city.', '["will live", "will be living", "will lived", "will be live"]', 1, 'Future continuous: will be + V-ing. "Next year" = extended period. Ongoing state during that time.', 'easy'),

-- MEDIUM (20 questions)
('foundation', 'tenses-advanced', 'intermediate', 'Difference: A) "I will work tomorrow." B) "I will be working tomorrow."', '["A = simple fact, B = emphasizes duration/ongoing", "A = ongoing, B = simple fact", "Both mean the same", "Both are wrong"]', 0, 'Will = simple future fact. Will be + V-ing = emphasizes action in progress/duration. B shows work as ongoing activity.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'What is wrong? "I will be work at 5 PM."', '["Use working instead of work", "Use worked instead of work", "Use works instead of work", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING (not base). Correct: "I will be working at 5 PM." Must use -ing form.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose correct: "This time next week, I _____ my exam."', '["will take", "will be taking", "will have taken", "will taken"]', 1, 'Future continuous: will be + V-ing. "This time next week" = specific future moment. Action in progress at that time.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: at / be / She / meeting / PM / will / 3 / a / attending', '["She will be attending a meeting at 3 PM", "She will be a meeting attending at 3 PM", "At 3 PM she will be attending a meeting", "She attending will be a meeting at 3 PM"]', 0, 'Pattern: Subject + will be + V-ing + object + time. Natural: She will be attending a meeting at 3 PM. Both orders work.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Polite future inquiry: "_____ you using this room tomorrow?"', '["Will", "Will be", "Are", "Were"]', 0, 'Future continuous question: Will + subject + be + V-ing? "Will you be using" = polite way to ask about future plans.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "They will be wait for us at the station."', '["Use waiting instead of wait", "Use waited instead of wait", "Use waits instead of wait", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING. Correct: "They will be waiting for us at the station." Must use -ing form.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Scene-setting: "When you arrive, I _____ dinner."', '["will cook", "will be cooking", "will have cooked", "cooked"]', 1, 'Future continuous for background action: will be + V-ing. "Will be cooking" = ongoing action when arrival happens. Scene-setting!', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Rearrange: working / be / time / this / next / will / We / year', '["We will be working this time next year", "We will be this time working next year", "This time next year we will be working", "We working will be this time next year"]', 0, 'Pattern: Subject + will be + V-ing + "this time next year". Natural: We will be working this time next year. Both orders work.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Difference: "I will call you" vs "I will be calling you"', '["First = simple action, second = softer/more tentative", "First = softer, second = direct", "Both mean the same", "Both are wrong"]', 0, 'Will = direct statement. Will be + V-ing = softer/more polite. "Will be calling" sounds less demanding/more tentative.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "Don''t call at 8 PM. I _____ dinner."', '["will have", "will be having", "will have had", "had"]', 1, 'Future continuous: will be + V-ing. "At 8 PM" = specific time. Action in progress at that moment. Natural conversational use.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "She will be go to Mumbai next week."', '["Use going instead of go", "Use went instead of go", "Use goes instead of go", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING. Correct: "She will be going to Mumbai next week." Must use -ing form.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: all / studying / be / will / They / night', '["They will be studying all night", "They will be all night studying", "All night they will be studying", "They studying will be all night"]', 0, 'Pattern: Subject + will be + V-ing + duration. Natural: They will be studying all night. Duration at end.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "At this time tomorrow, we _____ to Delhi."', '["will fly", "will be flying", "will have flown", "flew"]', 1, 'Future continuous: will be + V-ing. "At this time tomorrow" = specific future moment. Action in progress at that time.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "I will be worked from home next week."', '["Use working instead of worked", "Use work instead of worked", "Use works instead of worked", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING (not V3). Correct: "I will be working from home next week." Must use -ing.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Difference: "Will you help me?" vs "Will you be helping me?"', '["First = direct request, second = asking about plans", "First = asking about plans, second = direct", "Both mean the same", "Both are wrong"]', 0, 'Will = direct request/question. Will be + V-ing = asking about their plans (less direct). Second is softer inquiry.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "When you wake up, I _____ breakfast."', '["will make", "will be making", "will have made", "made"]', 1, 'Future continuous for background: will be + V-ing. "Will be making" = action in progress when you wake. Scene-setting!', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: exam / be / taking / will / tomorrow / morning / I / my', '["I will be taking my exam tomorrow morning", "I will be my exam taking tomorrow morning", "Tomorrow morning I will be taking my exam", "I taking will be my exam tomorrow morning"]', 0, 'Pattern: Subject + will be + V-ing + object + time. Natural: I will be taking my exam tomorrow morning. Both orders work.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "Will she be arrives at 5 PM?"', '["Use arriving instead of arrives", "Use arrived instead of arrives", "Use arrive instead of arrives", "Nothing wrong"]', 0, 'Future continuous question: Will + subject + be + V-ING? Correct: "Will she be arriving at 5 PM?" Must use -ing.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "Don''t disturb me tomorrow. I _____ for my exam."', '["will study", "will be studying", "will have studied", "studied"]', 1, 'Future continuous: will be + V-ing. "Tomorrow" = extended time. Action in progress during that period. Emphasizes duration!', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Rearrange: project / completing / be / will / week / next / We / the', '["We will be completing the project next week", "We will be the project completing next week", "Next week we will be completing the project", "We completing will be the project next week"]', 0, 'Pattern: Subject + will be + V-ing + object + time. Natural: We will be completing the project next week. Both orders work.', 'medium'),

-- HARD (11 questions)
('foundation', 'tenses-advanced', 'intermediate', 'Subtle difference: "I will work" vs "I will be working" in plans', '["First = definite decision, second = tentative/less committed", "First = tentative, second = definite", "Both mean the same", "Both are wrong"]', 0, 'Will = definite decision. Will be + V-ing = softer/more tentative. Continuous form sounds less committed/more flexible.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Which correctly shows polite inquiry about plans?', '["Will you attend the meeting tomorrow?", "Will you be attending the meeting tomorrow?", "Both equally polite", "Neither is polite"]', 1, 'Future continuous = more polite inquiry. "Will you be attending" = asking about their plans (not requesting). Less direct!', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "This time next year, I will be graduated."', '["Use will have graduated instead", "Use will graduate instead", "Use will be graduating instead", "Nothing wrong"]', 0, 'Momentary action (graduate) = future perfect (not continuous). Correct: "I will have graduated." Graduation = moment, not duration.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: year / living / be / this / will / next / time / We / Mumbai / in', '["We will be living in Mumbai this time next year", "We will be in Mumbai living this time next year", "This time next year we will be living in Mumbai", "We living will be in Mumbai this time next year"]', 0, 'Pattern: Subject + will be + V-ing + place + "this time next year". Natural: both orders work professionally.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "By 5 PM, I _____ for three hours."', '["will work", "will be working", "will have been working", "worked"]', 2, 'Duration by specific time = future perfect continuous. "Will have been working for three hours" = duration completed by that time.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "Next month, the company will be announce the results."', '["Use announcing instead of announce", "Use announced instead of announce", "Use announces instead of announce", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING. Correct: "The company will be announcing the results next month." Must use -ing.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Difference: "I will meet him tomorrow" vs "I will be meeting him tomorrow"', '["First = simple plan, second = already scheduled/arranged", "First = scheduled, second = simple", "Both mean the same", "Both are wrong"]', 0, 'Will = simple plan/decision. Will be + V-ing = already scheduled arrangement. Continuous implies pre-arrangement!', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "Don''t worry. By the time you arrive, I _____ everything."', '["will finish", "will be finishing", "will have finished", "finished"]', 2, 'Completion before future time = future perfect. "Will have finished" = action completed before arrival. Not continuous!', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: when / sleeping / be / will / you / She / arrive', '["She will be sleeping when you arrive", "She will be when you arrive sleeping", "When you arrive she will be sleeping", "She sleeping will be when you arrive"]', 0, 'Pattern: Subject + will be + V-ing + when + clause. Natural: She will be sleeping when you arrive. Both orders work.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "Will they be finish the project by Friday?"', '["Use finishing instead of finish", "Use have finished instead of be finish", "Use finished instead of finish", "Nothing wrong"]', 1, 'Completion by specific time = future perfect (not continuous). Correct: "Will they have finished the project by Friday?" By = completion.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "I _____ you next week about the decision."', '["will inform", "will be informing", "Both equally natural", "Neither is natural"]', 2, 'Both natural! Will = direct statement. Will be + V-ing = softer/more polite. Context determines which is better.', 'hard');

