-- EASY (20 questions)
('foundation', 'tenses-advanced', 'intermediate', 'I _____ studying for 2 hours.', '["have studied", "have been studying", "am studying", "studied"]', 1, 'Present perfect continuous: have/has been + V-ing. Shows duration from past to present. "Have been studying for 2 hours" = started 2 hours ago, still studying.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ waiting since morning.', '["has waited", "has been waiting", "is waiting", "waited"]', 1, 'Present perfect continuous: has been + V-ing. Duration from specific starting point to now. "Since morning" = ongoing action.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ working all day.', '["have worked", "have been working", "are working", "worked"]', 1, 'Present perfect continuous: have been + V-ing. "All day" = extended duration to present. Emphasizes ongoing nature.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'He _____ living here for 5 years.', '["has lived", "has been living", "is living", "lived"]', 1, 'Present perfect continuous: has been + V-ing. Duration with "for". Started 5 years ago, still living here now.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'We _____ learning English for months.', '["have learned", "have been learning", "are learning", "learned"]', 1, 'Present perfect continuous: have been + V-ing. Duration emphasis. "For months" = ongoing learning process to present.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'You _____ working too hard lately.', '["have worked", "have been working", "are working", "worked"]', 1, 'Present perfect continuous: have been + V-ing. "Lately" = recent period to now. Emphasizes continuous recent action.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'It _____ raining since yesterday.', '["has rained", "has been raining", "is raining", "rained"]', 1, 'Present perfect continuous: has been + V-ing. "Since yesterday" = specific starting point. Still raining now.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'The students _____ preparing for exams.', '["have prepared", "have been preparing", "are preparing", "prepared"]', 1, 'Present perfect continuous: have been + V-ing. Ongoing preparation from past to present. Duration emphasis.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'I _____ feeling tired recently.', '["have felt", "have been feeling", "am feeling", "felt"]', 1, 'Present perfect continuous: have been + V-ing. "Recently" = recent period to now. Ongoing state.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ working from home this week.', '["has worked", "has been working", "is working", "worked"]', 1, 'Present perfect continuous: has been + V-ing. "This week" = period from start of week to now. Ongoing action.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ playing cricket for hours.', '["have played", "have been playing", "are playing", "played"]', 1, 'Present perfect continuous: have been + V-ing. "For hours" = duration. Started hours ago, still playing.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'He _____ reading that book for weeks.', '["has read", "has been reading", "is reading", "read"]', 1, 'Present perfect continuous: has been + V-ing. "For weeks" = extended duration. Still reading now.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'We _____ watching this show lately.', '["have watched", "have been watching", "are watching", "watched"]', 1, 'Present perfect continuous: have been + V-ing. "Lately" = recent period. Repeated recent action to present.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'I _____ waiting for you for 30 minutes.', '["have waited", "have been waiting", "am waiting", "waited"]', 1, 'Present perfect continuous: have been + V-ing. "For 30 minutes" = duration. Started 30 min ago, still waiting.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'She _____ working on this project since Monday.', '["has worked", "has been working", "is working", "worked"]', 1, 'Present perfect continuous: has been + V-ing. "Since Monday" = starting point. Still working on it now.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'They _____ arguing all morning.', '["have argued", "have been arguing", "are arguing", "argued"]', 1, 'Present perfect continuous: have been + V-ing. "All morning" = duration. Started in morning, still arguing.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'He _____ feeling better recently.', '["has felt", "has been feeling", "is feeling", "felt"]', 1, 'Present perfect continuous: has been + V-ing. "Recently" = recent period. Ongoing improvement to present.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'We _____ discussing this issue for days.', '["have discussed", "have been discussing", "are discussing", "discussed"]', 1, 'Present perfect continuous: have been + V-ing. "For days" = extended duration. Ongoing discussion to now.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'You _____ doing great work this month.', '["have done", "have been doing", "are doing", "did"]', 1, 'Present perfect continuous: have been + V-ing. "This month" = period from start to now. Ongoing good work.', 'easy'),

('foundation', 'tenses-advanced', 'intermediate', 'It _____ snowing all night.', '["has snowed", "has been snowing", "is snowing", "snowed"]', 1, 'Present perfect continuous: has been + V-ing. "All night" = duration. Started last night, still snowing (or just stopped).', 'easy'),

-- MEDIUM (20 questions)
('foundation', 'tenses-advanced', 'intermediate', 'Difference: A) "I have worked here for 5 years." B) "I have been working here for 5 years."', '["A = finished, B = ongoing/temporary feeling", "A = ongoing, B = finished", "Both mean the same", "Both are wrong"]', 0, 'Present perfect = neutral fact. Present perfect continuous = emphasizes ongoing nature/temporary. B feels more temporary or emphasizes duration.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'What is wrong? "She has been go to the gym lately."', '["Use going instead of go", "Use went instead of go", "Use goes instead of go", "Nothing wrong"]', 0, 'Present perfect continuous: has been + V-ING. Correct: "She has been going to the gym lately." Must use -ing form.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "You look tired. What _____?"', '["have you done", "have you been doing", "are you doing", "did you do"]', 1, 'Present perfect continuous for recent activity causing present result. "What have you been doing?" = asking about activity that made you tired.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: for / been / working / have / hours / I / three', '["I have been working for three hours", "I have been for three hours working", "For three hours I have been working", "I working have been for three hours"]', 0, 'Pattern: Subject + have/has been + V-ing + for + duration. Natural: I have been working for three hours. Both orders work.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "They has been studying all day."', '["Use have instead of has", "Use had instead of has", "Use are instead of has", "Nothing wrong"]', 0, 'Subject-verb agreement: They = have (not has). Correct: "They have been studying all day." Plural = have.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "My hands are dirty. I _____ in the garden."', '["worked", "have worked", "have been working", "am working"]', 2, 'Present perfect continuous shows recent activity with present evidence. "Have been working" = explains dirty hands (present result).', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Rearrange: morning / been / waiting / has / She / since', '["She has been waiting since morning", "She has been since morning waiting", "Since morning she has been waiting", "She waiting has been since morning"]', 0, 'Pattern: Subject + has been + V-ing + since + time. Natural: She has been waiting since morning. Both orders work.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "I have been studied for 2 hours."', '["Use studying instead of studied", "Use study instead of studied", "Use studies instead of studied", "Nothing wrong"]', 0, 'Present perfect continuous: have been + V-ING (not V3). Correct: "I have been studying for 2 hours." Must use -ing.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "How long _____ English?"', '["do you learn", "have you learned", "have you been learning", "are you learning"]', 2, 'Duration question = present perfect continuous. "How long have you been learning English?" = asks about ongoing duration.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Difference: "It has rained" vs "It has been raining"', '["First = stopped, second = just stopped or still raining", "First = still raining, second = stopped", "Both mean the same", "Both are wrong"]', 0, 'Present perfect = completed. Present perfect continuous = recently completed or still ongoing. Second emphasizes duration/recent nature.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: lately / been / feeling / have / tired / You', '["You have been feeling tired lately", "You have been lately feeling tired", "Lately you have been feeling tired", "You feeling have been tired lately"]', 0, 'Pattern: Subject + have been + V-ing + adjective + time. Natural: You have been feeling tired lately. Both orders work.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "He have been working hard."', '["Use has instead of have", "Use had instead of have", "Use is instead of have", "Nothing wrong"]', 0, 'Subject-verb agreement: He = has (not have). Correct: "He has been working hard." Singular = has.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "Why are you so happy? What _____?"', '["happened", "has happened", "has been happening", "happens"]', 1, 'Recent event causing present state = present perfect. "What has happened?" = asking about completed event (not ongoing activity).', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Rearrange: weeks / been / for / reading / has / book / this / She', '["She has been reading this book for weeks", "She has been this book reading for weeks", "For weeks she has been reading this book", "She reading has been this book for weeks"]', 0, 'Pattern: Subject + has been + V-ing + object + for + duration. Natural: She has been reading this book for weeks.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "We been working on this project."', '["Add have: We have been working", "Add has: We has been working", "Add are: We are been working", "Nothing wrong"]', 0, 'Missing auxiliary! Need have/has. Correct: "We have been working on this project." Must have auxiliary verb.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "I''m exhausted. I _____ all day."', '["worked", "have worked", "have been working", "am working"]', 2, 'Recent continuous activity causing present state = present perfect continuous. "Have been working" = explains exhaustion.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: project / working / been / has / on / He / this / month / all', '["He has been working on this project all month", "He has been on this project working all month", "All month he has been working on this project", "He working has been on this project all month"]', 0, 'Pattern: Subject + has been + V-ing + on + object + duration. Natural: both orders work professionally.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "They has been been waiting."', '["Remove extra been AND use have instead of has", "Remove extra been", "Use have instead of has", "Nothing wrong"]', 0, 'Two errors: Double "been" + wrong auxiliary. Correct: "They have been waiting." They = have, only one "been".', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "Your eyes are red. _____ crying?"', '["Did you cry", "Have you cried", "Have you been crying", "Are you crying"]', 2, 'Recent activity with present evidence = present perfect continuous. "Have you been crying?" = explains red eyes.', 'medium'),

('foundation', 'tenses-advanced', 'intermediate', 'Rearrange: lately / watching / been / have / show / We / this', '["We have been watching this show lately", "We have been this show watching lately", "Lately we have been watching this show", "We watching have been this show lately"]', 0, 'Pattern: Subject + have been + V-ing + object + time. Natural: We have been watching this show lately. Both orders work.', 'medium'),

-- HARD (11 questions)
('foundation', 'tenses-advanced', 'intermediate', 'Stative verb: Which is wrong? A) "I have known him for years." B) "I have been knowing him for years."', '["B is wrong", "A is wrong", "Both correct", "Both wrong"]', 0, 'Stative verbs don''t use continuous! "Know" = state (not action). Correct: "I have known him." Stative = no continuous form.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Subtle difference: "I have lived in Mumbai" vs "I have been living in Mumbai"', '["First = permanent/neutral, second = temporary feeling", "First = temporary, second = permanent", "Both mean the same", "Both are wrong"]', 0, 'Present perfect = neutral/permanent feeling. Present perfect continuous = emphasizes temporary or emphasizes the living experience. Nuance!', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "Each student have been working hard."', '["Use has instead of have", "Use had instead of have", "Use is instead of have", "Nothing wrong"]', 0, 'Subject-verb agreement: "Each student" = singular = has. Correct: "Each student has been working hard." Each = singular.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: exams / weeks / been / have / for / preparing / for / They / three', '["They have been preparing for exams for three weeks", "They have been for exams preparing for three weeks", "For three weeks they have been preparing for exams", "They preparing have been for exams for three weeks"]', 0, 'Pattern: Subject + have been + V-ing + for + object + for + duration. Natural: both orders work. Duration typically at end.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "The road is wet. It _____."', '["rained", "has rained", "has been raining", "is raining"]', 2, 'Recent activity with present evidence = present perfect continuous. "Has been raining" = explains wet road (just stopped raining).', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "I have been finish my work."', '["Use finishing instead of finish", "Use finished instead of finish", "Use finishes instead of finish", "Nothing wrong"]', 0, 'Present perfect continuous: have been + V-ING. Correct: "I have been finishing my work." Must use -ing form.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Difference: "How many books have you read?" vs "What have you been reading?"', '["First = completed count, second = recent activity", "First = recent activity, second = count", "Both mean the same", "Both are wrong"]', 0, 'Present perfect = completed actions/count. Present perfect continuous = recent ongoing activity. Different focuses!', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Arrange: lately / improving / been / team / The / has', '["The team has been improving lately", "The team has been lately improving", "Lately the team has been improving", "The improving has been team lately"]', 0, 'Pattern: Subject + has been + V-ing + time. Natural: The team has been improving lately. Both orders work.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Error: "She has been win many awards."', '["Use winning instead of win", "Use won instead of win", "Use wins instead of win", "Nothing wrong"]', 0, 'Present perfect continuous: has been + V-ING. BUT "win" = repeated actions better with present perfect. Correct: "She has won many awards." Completed achievements = perfect (not continuous).', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Choose: "I''m tired because I _____ all day."', '["worked", "have worked", "have been working", "am working"]', 2, 'Recent continuous activity causing present tiredness = present perfect continuous. "Have been working" = explains current state.', 'hard'),

('foundation', 'tenses-advanced', 'intermediate', 'Rearrange: morning / waiting / been / since / for / have / you / I', '["I have been waiting for you since morning", "I have been for you waiting since morning", "Since morning I have been waiting for you", "I waiting have been for you since morning"]', 0, 'Pattern: Subject + have been + V-ing + for + object + since + time. Natural: both orders work professionally.', 'hard'),

